parameters.jsCode:
// Process Ordefy HTTP response
const item = $input.first();
const original = $('Extract & Route').first().json;
const phone = original.phone || '';
const digits = phone.replace(/\D/g, '');

// Parse Ordefy response
let orders = [];
try {
  const response = item.json;
  orders = Array.isArray(response) ? response : (response.orders || response.data || []);
} catch(e) {}

const pendingOrders = orders.filter(o =>
  o.status === 'pending' || o.status === 'contacted' || o.status === 'confirmed' || o.status === 'shipped' ||
  o.sleeves_status === 'pending' || o.sleeves_status === 'contacted' || o.sleeves_status === 'confirmed' || o.sleeves_status === 'shipped'
);
const completedOrders = orders.filter(o =>
  o.status === 'delivered' || o.status === 'completed' ||
  o.sleeves_status === 'delivered' || o.sleeves_status === 'completed'
);

let customerStatus = 'NUEVO';
if (pendingOrders.length > 0) customerStatus = 'TIENE_ORDEN_PENDIENTE';
else if (completedOrders.length > 0) customerStatus = 'CLIENTE_RECURRENTE';

const hasPendingTransfer = pendingOrders.length > 0 && pendingOrders[0].payment_method === 'pending';

// Sort pending orders by created_at DESC, take the most recent
const sortedPending = [...pendingOrders].sort((a, b) => {
  const da = new Date(a.created_at || 0);
  const db = new Date(b.created_at || 0);
  return db - da;
});
const latestPending = sortedPending[0] || null;

// Determine if we need to resend the confirmation template.
// Conditions: latest order is pending/contacted, template was NOT already sent
// (or template flag expired), and the current route is not already handling
// the order (template_reply, maps_reply, web_order, template_cancel).
const templateSent = original.template_sent || false;
const route = original.route || '';
const handledRoutes = ['template_reply', 'maps_reply', 'web_order', 'template_cancel', 'cancellation_reason'];
const isPendingStatus = latestPending && (latestPending.status === 'pending' || latestPending.status === 'contacted');
const needsTemplateResend = isPendingStatus && !templateSent && !handledRoutes.includes(route);

// Build resend order data from the Ordefy order if needed
let resendOrderData = null;
if (needsTemplateResend && latestPending) {
  const o = latestPending;
  const items = o.items || o.line_items || [];
  const firstItem = items[0] || {};
  const productName = firstItem.name || firstItem.product_name || 'PDRN Serum Solenne';
  const totalQty = items.reduce((sum, i) => sum + (i.quantity || 1), 0);
  const totalPrice = o.total_price || o.total || 0;
  const fmtTotal = Number(totalPrice).toLocaleString('es-PY');
  const customerName = o.customer_name || original.name || 'Cliente';
  const mapsLink = o.google_maps_url || o.google_maps_link || '';
  const city = o.city || o.shipping_city || '';
  const address = o.address || o.shipping_address?.address || '';
  const hasGPS = !!(mapsLink && mapsLink.length > 10 && mapsLink.includes('google'));
  const addressText = address || city || 'Direccion pendiente';

  const productMap = {
    'PDRN Pink Peptide Serum - Personal': 'PDRN Serum Personal',
    'PDRN Pink Peptide Serum - Kit Duo': 'PDRN Serum Kit Duo'
  };
  let productDisplay = productMap[productName] || productName;
  if (totalQty === 2) productDisplay = 'Kit Duo (2 PDRN Serum)';
  if (totalQty === 3) productDisplay = 'Kit Familiar (3 PDRN Serum)';

  resendOrderData = {
    phone: phone,
    customer_name: customerName,
    product: productDisplay,
    total: fmtTotal,
    total_raw: totalPrice,
    quantity: totalQty,
    order_number: o.order_number || '',
    maps_link: mapsLink,
    city: city,
    address: addressText,
    has_gps: hasGPS,
    payment_method: o.payment_method || 'pending',
    payment_status: o.financial_status || 'pending'
  };
}

return { json: {
  ...original,
  phone_digits: digits,
  customer_status: customerStatus,
  has_pending_order: pendingOrders.length > 0,
  has_pending_transfer: hasPendingTransfer,
  pending_orders: pendingOrders,
  order_history: orders,
  pending_order_number: pendingOrders[0]?.order_number || null,
  needs_template_resend: needsTemplateResend,
  resend_order_data: resendOrderData
}};

