// Parse the OpenAI splitter response
const item = $input.first();
const original = $('Extract & Route').first().json;
const sofiaOutput = $('Sofia Error Check').first().json.output || '';

let parte1 = sofiaOutput;
let parte2 = '';
let parte3 = '';

try {
  const choices = item.json.choices;
  if (choices && choices[0]?.message?.content) {
    const parsed = JSON.parse(choices[0].message.content);
    parte1 = parsed.parte1 || sofiaOutput;
    parte2 = parsed.parte2 || '';
    parte3 = parsed.parte3 || '';
  }
} catch (e) {
  parte1 = sofiaOutput;
}

// Clean ALL action markers from the parts (safety: strips any leftover markers)
const clean = (t) => t
  .replace(/SEND_MEDIA\s*[:\-]?\s*(foto_producto_naranja|foto_producto|lista_precios|pack_comparativo)/gi, '')
  .replace(/ORDER_CONFIRMED\s*[:\-]?\s*\w*/gi, '')
  .replace(/HUMAN_HANDOFF\s*[:\-]?\s*\w*/gi, '')
  .replace(/\{[^}]*"action"\s*:\s*"(SEND_MEDIA|ORDER_CONFIRMED|HUMAN_HANDOFF)"[^}]*\}/g, '')
  .trim();

return { json: {
  ...original,
  sofia_output: sofiaOutput,
  parte1: clean(parte1),
  parte2: clean(parte2),
  parte3: clean(parte3),
  has_part2: clean(parte2).length > 0,
  has_part3: clean(parte3).length > 0,
  trigger_send_media: false,
  trigger_media_type: null
}};

