}

dynamicParts.push('[DATOS DEL CLIENTE - USA ESTOS VALORES EXACTOS EN LAS TOOLS]\nphone: ' + phone + '\nconversation_id: ' + conversationId + '\naccount_id: ' + accountId + '\nname: ' + clientName + '\ncustomer_status: ' + customerStatus + '\nis_web_order: ' + isWebOrder + '\nhora_paraguay: ' + horaInfo + '\nminutos_desde_ultimo_mensaje: ' + minutosSinceMsg + '\nimagen_enviada: ' + imagenEnviada + (googleMapsUrl ? '\ngoogle_maps_url: ' + googleMapsUrl : '') + '\n[FIN DATOS]');

// Real-time stock from Ordefy
let stockSerumCtx = 0, stockDuoCtx = 0;
try {
  const sbKeyOrd = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZncWVjcXFsZXVvd3ZvaW1jb3hnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjcwNTY5NzcsImV4cCI6MjA4MjYzMjk3N30.aRX16e_vGkRgYN1RNMjF8bAOK8PmvwoFYFjGDEfa-YI';
  const stockRes = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://vgqecqqleuowvoimcoxg.supabase.co/rest/v1/products?select=sku,stock&store_id=eq.0b3f13f8-d1dc-48a5-a707-27a095c9c545&sku=in.(SOLENNE-SERUM-PERSONAL,SOLENNE-SERUM-DUO)',
    headers: { 'apikey': sbKeyOrd, 'Authorization': 'Bearer ' + sbKeyOrd },
