  });
  const sRows = Array.isArray(stockRes) ? stockRes : [];
  for (const r of sRows) {
    if (r.sku === 'SOLENNE-SERUM-PERSONAL') stockSerumCtx = r.stock || 0;
    if (r.sku === 'SOLENNE-SERUM-DUO') stockDuoCtx = r.stock || 0;
  }
} catch(e) { stockSerumCtx = -1; stockDuoCtx = -1; }
const serumStatus = stockSerumCtx < 0 ? 'desconocido' : (stockSerumCtx > 0 ? 'En stock (' + stockSerumCtx + ' uds)' : 'AGOTADO');
const duoStatus = stockDuoCtx < 0 ? 'desconocido' : (stockDuoCtx > 0 ? 'En stock (' + stockDuoCtx + ' uds)' : 'AGOTADO');
dynamicParts.push('[STOCK ACTUAL]\nROJOS: ' + serumStatus + '\nNARANJAS: ' + duoStatus + '\nIMPORTANTE: Si un producto esta AGOTADO, NO lo ofrezcas. Informale que no esta disponible.\n[FIN STOCK]');

// 2. Pending order block
if (customerStatus === 'TIENE_ORDEN_PENDIENTE' && original.pending_orders && original.pending_orders.length > 0) {
