try {
const body = $input.item.json.body;
if (!body || body.message_type !== 'incoming') return { json: { skip: true } };

const content = (body.content || '').trim();
const triggerId = body.id || '';
const triggerSourceId = body.source_id || '';
const conv = body.conversation || {};
const convId = conv.id || '';

const contactMeta = conv.meta?.sender || {};
const phone = contactMeta.phone_number || '';
const name = contactMeta.name || '';
const fn = name.split(' ')[0] || '';
const ctid = contactMeta.id || '';
const aid = body.account?.id || '';

const attachments = body.attachments || [];

const HANDOFF_LABELS = ['humano', 'reclamo', 'venta'];
const convLabels = conv.labels || [];
if (convLabels.some(l => HANDOFF_LABELS.includes(l))) return { json: { skip: true } };

const hasAudioAttachment = attachments.some(a => a.file_type === 'audio');
if (!content && !attachments.length) return { json: { skip: true } };

const n = (content || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// Greeting-stripping: if content has buffered messages (newlines) or sofia is already active,
// remove pure greeting lines before classifying so "Hola\nCuanto cuestan?" routes to precio, not saludo
const sofiaActiveRawEarly = contactMeta.custom_attributes?.sofia_active;
const lastSofiaTimeEarly = contactMeta.custom_attributes?.last_sofia_time;
const sofiaWasActiveEarly = (sofiaActiveRawEarly === true || sofiaActiveRawEarly === 'true') &&
  lastSofiaTimeEarly &&
  (Date.now() - new Date(lastSofiaTimeEarly).getTime()) < 30 * 60 * 1000;

const GREETING_ONLY_RE = /^(hola|buenas|buen dia|buenas tardes|buenas noches|hey|hi)[\s!.,]*$/;

let nClassify = n;
if (sofiaWasActiveEarly || n.includes('\n')) {
  const lines = n.split('\n');
  const nonGreetingLines = lines.filter(l => !GREETING_ONLY_RE.test(l.trim()));
  nClassify = nonGreetingLines.join(' ').trim() || n;
}

const isWeb = n.includes('acabo de completar mi pedido') || n.includes('orden: #sol-') || (n.includes('solenne') && n.includes('mis datos:'));
let od = null;
if (isWeb) {
  const om = content.match(/#SOL-[\w-]+/);
  const mm = content.match(/https?:\/\/(www\.)?google\.com\/maps\S*/);
  od = { orderNumber: om?.[0] || '', hasMapsLink: !!mm, mapsLink: mm?.[0] || '' };
}

const hasLocationAttachment = attachments
  .some(a => a.file_type === 'location' || a.data_type === 'location');
const hasImageAttachment = attachments
  .some(a => a.file_type === 'image' || a.file_type === 'file');

const isMapsReply = !isWeb && (
  /google\.com\/maps|maps\.google|goo\.gl\/maps|maps\.app\.goo\.gl/.test(n) ||
  hasLocationAttachment
);

if (isMapsReply) {
  if (hasLocationAttachment) {
    const locAtt = attachments.find(a => a.file_type === 'location' || a.data_type === 'location');
    const lat = locAtt?.coordinates_lat || locAtt?.latitude || locAtt?.data?.latitude;
    const lng = locAtt?.coordinates_long || locAtt?.longitude || locAtt?.data?.longitude;
    od = {
      orderNumber: '',
      hasMapsLink: true,
      mapsLink: (lat && lng) ? 'https://www.google.com/maps?q=' + lat + ',' + lng : '',
      latitude: lat,
      longitude: lng
    };
  } else {
    const mm = content.match(/https?:\/\/\S*(?:google\.com\/maps|maps\.google|goo\.gl\/maps|maps\.app\.goo\.gl)\S*/);
    od = { orderNumber: '', hasMapsLink: true, mapsLink: mm?.[0] || '' };
  }
}

const contactGastonKeywords = /hablar con gaston|contactar a gaston|quiero hablar con el dueno|pasame con gaston|persona real|hablar con una persona|agente humano|quiero hablar con alguien/;
const isContactGaston = !isWeb && !isMapsReply && contactGastonKeywords.test(n);

const complaintKeywords = /problema|reclamo|queja|estafa|denuncia|defectuoso|roto|danado/;
const postDeliveryIssues = /no me llego|no llego|no enviaron|no entregaron|no recibi|no llega|nunca llego|pedido perdido|sigo esperando|no me mandaron|donde esta mi pedido|donde esta mi envio|no me llega/;
const negativeExtreme = /pesimo|horrible|malisimo|malismo|porqueria|basura|robo|fraude|arrepiento|devuelvan|devuelvanme|me enganaron|me mintieron|los voy a denunciar/;
const productIssues = /se rompio|se rayo|vino roto|vino rayado|vino mal|esta roto|esta rayado|no funciona|no sirve|no carga|no anda/;

const isComplaint = !isWeb && !isMapsReply && !isContactGaston && (
  complaintKeywords.test(n) ||
  postDeliveryIssues.test(n) ||
  negativeExtreme.test(n) ||
  productIssues.test(n)
);

const wholesaleKeywords = /por mayor|mayorista|mayoreo|revender|reventa|distribuidora|al por mayor|cantidad grande|compra grande|para tienda|para negocio|para local/;
const isWholesale = !isWeb && !isMapsReply && !isContactGaston && !isComplaint && wholesaleKeywords.test(n);

let fr = null, fc = null, fclose = null;

// Read FAQ state BEFORE FAQ block (used for conditional greeting in precio)
const lastCat = contactMeta.custom_attributes?.last_faq_category;
const lastTime = contactMeta.custom_attributes?.last_faq_time;

if (hasAudioAttachment && !content && !isWeb && !isMapsReply && !isContactGaston && !isComplaint && !isWholesale) {
  fc = 'audio';
  fr = 'Disculpe, por el momento no podemos procesar mensajes de audio. Nos podria escribir su consulta por texto? Asi le ayudamos enseguida!';
}

if (!fc && !isWeb && !isMapsReply && !isContactGaston && !isComplaint && !isWholesale) {
  if (/envio|envian|envias|delivery|demora|demoran|llega|cuanto tarda|cuanto demoran|cuanto tiempo|tiempo de entrega/.test(nClassify)) { fc = 'envio'; fr = 'Hacemos envios GRATIS a todo Asuncion y Gran Asuncion\nPara el interior del pais trabajamos con transportadoras, el costo depende de la ciudad\n\nTe gustaria hacer tu pedido?'; }
  else if (/precio|cuanto|costo|cuesta|vale/.test(nClassify)) {
    fc = 'precio';
    const recentlyGreeted = lastCat === 'saludo' && lastTime && (Date.now() - new Date(lastTime).getTime()) < 5 * 60 * 1000;
    fr = (recentlyGreeted ? '' : ('Buenas ' + fn + '! un gusto saludarte\n\n')) + 'Estos son nuestros precios:\n1 Lente Personal: 229.000 Gs\nKit Duo (2 lentes): 349.000 Gs \nKit Familiar (3 lentes): 489.000 Gs\nDisponibles en rojo y naranja, mismo precio. Se pueden combinar colores\n\nEl envio en Gran Asuncion le sale Gratis';
    fclose = 'Que le parecen?';
  }
  else if (/foto|fotos|imagen|como son/.test(nClassify)) {
    fc = 'fotos';
    fr = 'Asi se ven los PDRN Serum de Solenne';
    fclose = 'Que le parecen?';
  }
  else if (/local|tienda|donde estan|pasar a buscar|retirar/.test(nClassify)) { fc = 'local'; fr = 'No contamos con local fisico, trabajamos solo por delivery y envios\nEl envio es GRATIS en Asuncion y Gran Asuncion\n\nTe gustaria que le enviemos los suyos?'; }
  else if (/naranja|orange/.test(nClassify)) { fc = 'colores'; fr = 'Los Kit Duos ya estan disponibles!\nTambien tenemos los rojos que son nuestra edicion mas popular\nTienen el mismo precio\n\nLe reservamos uno?'; }
  else if (/encima|arriba|sobre mis lentes|con mis lentes|encima.*receta|receta.*encima/.test(nClassify)) { fc = 'encima'; fr = 'Personalmente yo los uso encima de mis lentes de vista y es cuestion de cada uno y de acostumbrarse\n\nTe gustaria conocer mas sobre nuestros lentes?'; }
  else if (/graduacion|graduado|receta|medida|aumento/.test(nClassify)) { fc = 'graduacion'; fr = 'Nuestros lentes no tienen graduacion propia, pero se pueden usar encima de lentes de receta\nEl dueno los usa asi personalmente y funciona bien\n\nLe interesaria probarlo?'; }
  else if (/garantia|devolver|devolucion|cambio/.test(nClassify)) { fc = 'garantia'; fr = 'Ante cualquier inconveniente con tu pedido, le hacemos el reembolso completo\nTu compra esta 100% protegida con nosotros\n\nTe gustaria hacer tu pedido?'; }
  else if (/proveedor|proveedores|procedencia|origen|donde fabrican|de donde son|de donde vienen|importado|fabricante/.test(nClassify)) { fc = 'procedencia'; fr = 'Nuestros lentes son importados directamente de Brasil\nSon lentes especializados en bloqueo de luz azul de alta calidad\n\nTe gustaria conocer nuestros precios?'; }
  else if (/stock|disponible|disponibles|quedan|hay lentes|tienen lentes/.test(nClassify)) {
    fc = 'stock';
    let stockRojo = 0, stockNaranja = 0;
    try {
      const sbKeyOrdefy = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZncWVjcXFsZXVvd3ZvaW1jb3hnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjcwNTY5NzcsImV4cCI6MjA4MjYzMjk3N30.aRX16e_vGkRgYN1RNMjF8bAOK8PmvwoFYFjGDEfa-YI';
      const stockData = await $helpers.httpRequest({
        method: 'GET',
        url: 'https://vgqecqqleuowvoimcoxg.supabase.co/rest/v1/products?select=sku,stock&store_id=eq.0b3f13f8-d1dc-48a5-a707-27a095c9c545&sku=in.(SOLENNE-PDRN-30ML,SOLENNE-PDRN-DUO)',
        headers: { 'apikey': sbKeyOrdefy, 'Authorization': 'Bearer ' + sbKeyOrdefy },
        timeout: 3000
      });
      const rows = Array.isArray(stockData) ? stockData : [];
      for (const r of rows) {
        if (r.sku === 'SOLENNE-PDRN-30ML') stockRojo = r.stock || 0;
        if (r.sku === 'SOLENNE-PDRN-DUO') stockNaranja = r.stock || 0;
      }
    } catch(e) { stockRojo = 1; stockNaranja = 1; }
    const rojoDisp = stockRojo > 0;
