    if (rojoDisp && naranjaDisp) {
      fr = 'Si! Tenemos PDRN Serum y naranjas en stock, listos para envio\nHacemos envio GRATIS en Asuncion y Gran Asuncion\n\nTe gustaria recibir los suyos?';
    } else if (rojoDisp && !naranjaDisp) {
      fr = 'Tenemos los PDRN Serum disponibles y listos para envio\nLos naranjas estan agotados por el momento\nHacemos envio GRATIS en Asuncion y Gran Asuncion\n\nTe gustaria recibir los suyos?';
    } else if (!rojoDisp && naranjaDisp) {
