    } else {
      fr = 'Por el momento estamos sin stock, pero estamos por recibir mas unidades pronto\nSi quiere le aviso apenas lleguen!';
    }
  }
  else if (/(?:vi|visite|encontre|entre a).{0,30}(?:web|pagina|sitio|tienda online)|(?:desde|en) (?:la |su )?(?:web|pagina|sitio)|estaba.{0,20}(?:comprar|comprando|por comprar)/.test(nClassify)) {
    fc = 'web_lead';
    fr = 'Buenas ' + fn + '!, un gusto saludarle, como podemos ayudarle?';
  }
  else if (GREETING_ONLY_RE.test(nClassify) || (!nClassify.trim() && GREETING_ONLY_RE.test(n))) {
    const saludoRecent = lastCat === 'saludo' && lastTime && (Date.now() - new Date(lastTime).getTime()) < 2 * 60 * 60 * 1000;
    const sofiaWasActive = sofiaWasActiveEarly;
    if (saludoRecent || sofiaWasActive) {
      fc = null; fr = null; fclose = null;
    } else {
      fc = 'saludo';
      const bienvenida = (fn && fn.toLowerCase().endsWith('a')) ? 'Bienvenida' : 'Bienvenido';
      fr = 'Hola ' + fn + '! ' + bienvenida + ' a Solenne\nOfrecemos skincare K-beauty premium para descanso visual';
      fclose = 'Que te gustaria saber?';
