// Cancellation pending check (customer already said cancel, waiting for reason)
let cancellationPending = false;
const cancellationPendingRaw = contactMeta.custom_attributes?.cancellation_pending;
const cancellationPendingAt = contactMeta.custom_attributes?.cancellation_pending_at;
if (cancellationPendingRaw === true || cancellationPendingRaw === 'true') {
  if (cancellationPendingAt) {
    const cancelElapsed = Date.now() - new Date(cancellationPendingAt).getTime();
    cancellationPending = cancelElapsed < 24 * 60 * 60 * 1000;
  } else {
    cancellationPending = true;
  }
}

// Template sent check with 48h expiry
let templateSent = false;
const templateSentRaw = contactMeta.custom_attributes?.template_sent;
const templateSentAt = contactMeta.custom_attributes?.template_sent_at;
if ((templateSentRaw === true || templateSentRaw === 'true') && templateSentAt) {
  const elapsed = Date.now() - new Date(templateSentAt).getTime();
  templateSent = elapsed < 48 * 60 * 60 * 1000;
}
let templateOrderData = contactMeta.custom_attributes?.template_order_data || null;
let isPostPurchase = false;
let postPurchaseAge = null;
let postPurchaseData = null;

// Cancellation detection (within template context)
const cancelShort = /^(no|cancelar|cancelo|quiero cancelar|no quiero|no gracias|cancelado|anular|anulo)[\s,!.]*$/i;
const cancelLong = /cancelar\s+(el\s+|mi\s+)?(pedido|orden|compra)|no\s+(quiero|deseo|voy\s+a)\s+(comprar|pedir|ordenar|continuar)|ya\s+no\s+(quiero|me\s+interesa)/i;
const isTemplateCancel = templateSent && (cancelShort.test(content.trim()) || cancelLong.test(content.trim()));

const shortConfirm = /^(si|s[i\u00ed]+|sip|confirmo|dale|ok|listo|claro|perfecto|bueno)[\s,!.]*$/i;
const longConfirm = /^s[i\u00ed][,!.\s]*(confirmo|claro|dale|ok|listo|quiero|por favor)/i;
const isTemplateConfirm = templateSent && !isTemplateCancel && (shortConfirm.test(content.trim()) || longConfirm.test(content.trim()));
const isTemplateLocation = templateSent && hasLocationAttachment;
const isTemplateReply = isTemplateConfirm || isTemplateLocation;

let route = 'ai_needed';
if (cancellationPending) route = 'cancellation_reason';
else if (isTemplateCancel && !sofiaActive) route = 'template_cancel';
else if (isTemplateReply && !sofiaActive) route = 'template_reply';
else if (isWeb) route = 'web_order';
else if (isMapsReply && !sofiaActive) route = 'maps_reply';
else if (isContactGaston) route = 'contact_gaston';
else if (isComplaint) route = 'complaint';
else if (isWholesale) route = 'wholesale';
else if (fr) route = 'faq';

return { json: {
  skip: false, route, content, phone, name, first_name: fn,
  contact_id: ctid, conversation_id: convId, message_id: triggerId,
  source_id: triggerSourceId, account_id: aid,
  is_web_order: isWeb, is_maps_reply: isMapsReply, is_complaint: isComplaint,
  is_wholesale: isWholesale, is_contact_gaston: isContactGaston, order_data: od,
  template_sent: templateSent,
  template_order_data: templateOrderData,
  is_template_reply: isTemplateReply,
  is_template_cancel: isTemplateCancel,
  cancellation_pending: cancellationPending,
  is_post_purchase: isPostPurchase, post_purchase_age_hours: postPurchaseAge, post_purchase_data: postPurchaseData,
  is_template_confirm: isTemplateConfirm, is_template_location: isTemplateLocation,
  faq_category: fc, faq_response: fr, faq_closing: fclose,
  has_attachment: !!(attachments.length),
  has_location_attachment: hasLocationAttachment,
  has_image_attachment: hasImageAttachment,
  has_audio_attachment: hasAudioAttachment
}};
} catch (err) {
  return [{ json: { skip: true, error: err.message, route: 'error' } }];
}

