- confirm_order dos veces ni sin checklist completo
- Saludar sin hora correcta ni nombre del cliente
- Anunciar acciones futuras ('Despues te consulto', 'Luego te pregunto') -- hacer cuando corresponda sin avisar
- Ofrecer fotos o send_media post-compra o tras confirm_order exitoso
- Enviar mas de UN cierre por conversacion. Si ya usaste un cierre ('que tengas buen dia', 'que te vaya bien', etc.) y el cliente sigue escribiendo: responder directo a lo que dice, sin agregar otro cierre al final de tu respuesta";

// ===== BUILD DYNAMIC CONTEXT =====
const dynamicParts = [];

// 1. Client data block
const phone = original.phone || '';
const conversationId = original.conversation_id || '';
const accountId = original.account_id || '9';
const clientName = original.name || '';
const customerStatus = original.customer_status || 'NUEVO';
const isWebOrder = original.is_web_order || false;

const pyNow = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Asuncion' }));
const pyHour = pyNow.getHours();
const pyMins = String(pyNow.getMinutes()).padStart(2, '0');
const pyTimeStr = pyHour + ':' + pyMins;
const isDespacho = pyHour >= 14 && pyHour < 17;
const horaInfo = isDespacho ? pyTimeStr + ' [HORARIO DE DESPACHO ACTIVO]' : pyTimeStr;

// Check minutes since last message in this conversation (to skip greeting if < 5h)
let minutosSinceMsg = 9999;
if (conversationId) {
  try {
    const sbKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFhcHFoaHlmem1na3Z6dnRvbHVxIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzI3NTY2MTksImV4cCI6MjA4ODMzMjYxOX0.Y8JG5KpII8g3URK_v7F5jxvKW9xge93PjnnTQbl9lkM';
    const histCheck = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://qapqhhyfzmgkvzvtoluq.supabase.co/rest/v1/solenne_chat_histories?session_id=eq.' + conversationId + '&order=id.desc&limit=1',
      headers: {
        'apikey': sbKey,
        'Authorization': 'Bearer ' + sbKey
      }
    });
    const rows = Array.isArray(histCheck) ? histCheck : [];
    if (rows.length > 0 && rows[0].created_at) {
      const lastTs = new Date(rows[0].created_at).getTime();
      minutosSinceMsg = Math.round((Date.now() - lastTs) / 60000);
    }
  } catch(e) { /* keep default */ }
}

// Check if images were already sent via custom_attribute (fast, reliable)
let imagenEnviada = false;
if (original.contact_id) {
  try {
    const contactData = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://chat.thebrightidea.ai/api/v1/accounts/' + accountId + '/contacts/' + original.contact_id,
      headers: { 'api_access_token': 'CHATWOOT_TOKEN_REDACTED' }
    });
    const attrs = contactData?.custom_attributes || {};
    imagenEnviada = attrs.product_images_sent === true || attrs.product_images_sent === 'true';
  } catch(e) {
    // Fallback: scan Chatwoot private notes
    try {
      const cwMessages = await $helpers.httpRequest({
        method: 'GET',
        url: 'https://chat.thebrightidea.ai/api/v1/accounts/' + accountId + '/conversations/' + conversationId + '/messages',
        headers: { 'api_access_token': 'CHATWOOT_TOKEN_REDACTED' }
      });
      const msgs = Array.isArray(cwMessages?.payload) ? cwMessages.payload : [];
      imagenEnviada = msgs.some(m =>
        m.private === true &&
        m.content &&
        (m.content.toLowerCase().includes('magen') || m.content.toLowerCase().includes('foto_') || m.content.toLowerCase().includes('foto '))
      );
    } catch(e2) { /* default false */ }
  }
}

// Compute google_maps_url from current message's order_data (WhatsApp location pin or maps link)
let googleMapsUrl = '';
const orderDataGps = original.order_data;
if (orderDataGps) {
  if (orderDataGps.latitude && orderDataGps.longitude) {
    googleMapsUrl = 'https://maps.google.com/?q=' + orderDataGps.latitude + ',' + orderDataGps.longitude;
  } else if (orderDataGps.mapsLink) {
    googleMapsUrl = orderDataGps.mapsLink;
  }
}

dynamicParts.push('[DATOS DEL CLIENTE - USA ESTOS VALORES EXACTOS EN LAS TOOLS]
phone: ' + phone + '
conversation_id: ' + conversationId + '
account_id: ' + accountId + '
name: ' + clientName + '
customer_status: ' + customerStatus + '
is_web_order: ' + isWebOrder + '
hora_paraguay: ' + horaInfo + '
minutos_desde_ultimo_mensaje: ' + minutosSinceMsg + '
imagen_enviada: ' + imagenEnviada + (googleMapsUrl ? '
google_maps_url: ' + googleMapsUrl : '') + '
[FIN DATOS]');

// Real-time stock from Ordefy
let stockRojoCtx = 0, stockNaranjaCtx = 0;
try {
  const sbKeyOrd = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZncWVjcXFsZXVvd3ZvaW1jb3hnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjcwNTY5NzcsImV4cCI6MjA4MjYzMjk3N30.aRX16e_vGkRgYN1RNMjF8bAOK8PmvwoFYFjGDEfa-YI';
  const stockRes = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://vgqecqqleuowvoimcoxg.supabase.co/rest/v1/products?select=sku,stock&store_id=eq.0b3f13f8-d1dc-48a5-a707-27a095c9c545&sku=in.(SOLENNE-PDRN-30ML,SOLENNE-PDRN-DUO)',
    headers: { 'apikey': sbKeyOrd, 'Authorization': 'Bearer ' + sbKeyOrd },
    timeout: 3000
  });
  const sRows = Array.isArray(stockRes) ? stockRes : [];
  for (const r of sRows) {
    if (r.sku === 'SOLENNE-PDRN-30ML') stockRojoCtx = r.stock || 0;
    if (r.sku === 'SOLENNE-PDRN-DUO') stockNaranjaCtx = r.stock || 0;
  }
} catch(e) { stockRojoCtx = -1; stockNaranjaCtx = -1; }
const rojoStatus = stockRojoCtx < 0 ? 'desconocido' : (stockRojoCtx > 0 ? 'En stock (' + stockRojoCtx + ' uds)' : 'AGOTADO');
const naranjaStatus = stockNaranjaCtx < 0 ? 'desconocido' : (stockNaranjaCtx > 0 ? 'En stock (' + stockNaranjaCtx + ' uds)' : 'AGOTADO');
dynamicParts.push('[STOCK ACTUAL]
ROJOS: ' + rojoStatus + '
NARANJAS: ' + naranjaStatus + '
IMPORTANTE: Si un color esta AGOTADO, NO lo ofrezcas. Si el cliente lo pide, informale que no esta disponible y ofrece el otro color.
[FIN STOCK]');

// 2. Pending order block
if (customerStatus === 'TIENE_ORDEN_PENDIENTE' && original.pending_orders && original.pending_orders.length > 0) {
  const po = original.pending_orders[0];
  const items = po.items || [];
  const productItems = items.filter(i => !i.is_upsell);
  const itemsDesc = productItems.map(i =>
    (i.quantity || 1) + 'x ' + (i.name || i.sku || 'Producto')
  ).join(', ');
  const total = po.totals?.total || po.total || '';
  const addr = po.shipping_address?.address || '';
  const city = po.shipping_address?.city || '';
  const pmMap = { 'pending': 'transferencia', 'cash_on_delivery': 'contra_entrega' };
  const pm = pmMap[po.payment_method] || po.payment_method || '';

  dynamicParts.push('[ORDEN PENDIENTE DEL CLIENTE]
' +
    'Pedido #: ' + (po.order_number || 'N/A') + '
' +
    'Producto: ' + (itemsDesc || 'N/A') + '
' +
    (total ? 'Total: ' + Number(total).toLocaleString('es-PY') + ' Gs
' : '') +
    (addr ? 'Direccion: ' + addr + '
' : '') +
    (city ? 'Ciudad: ' + city + '
' : '') +
    (pm ? 'Forma de pago: ' + pm + '
' : '') +
    'Estado: ' + (po.status || 'pendiente') + '
' +
    '[FIN ORDEN PENDIENTE]');
}

// 3. KB context
let kbContext = '';
try {
  const kbResult = $('Fetch Knowledge Base').all();
  const kbData = kbResult.map(i => i.json);
  const entries = Array.isArray(kbData) && kbData.length > 0 && Array.isArray(kbData[0]) ? kbData[0] : kbData;
  if (entries.length > 0 && entries[0]?.category) {
    const msgLower = (original.content || '').toLowerCase();
    const matched = entries.filter(e => {
      if (!e.trigger_keywords || !Array.isArray(e.trigger_keywords)) return false;
      return e.trigger_keywords.some(kw => msgLower.includes(kw.toLowerCase()));
    });
    const toUse = matched.length > 0 ? matched : entries.slice(0, 5);
    kbContext = '--- CONTEXTO KB RELEVANTE ---
' + toUse.map(e =>
      '- [' + e.category + '] ' + e.content
    ).join('
').slice(0, 2000) + '
--- FIN CONTEXTO KB ---';
    dynamicParts.push(kbContext);
  }
} catch (e) { /* KB fetch failed, continue */ }

// 4. Few-shot examples
let fewShotContext = '';
try {
  const fsResult = $('Fetch Few-Shot').all();
  const fsData = fsResult.map(i => i.json);
  const entries = Array.isArray(fsData) && fsData.length > 0 && Array.isArray(fsData[0]) ? fsData[0] : fsData;
  if (entries.length > 0 && entries[0]?.scenario) {
    fewShotContext = '--- EJEMPLOS DE REFERENCIA ---
' + entries.map(e =>
      'Escenario: ' + e.scenario + '
' + e.conversation_text + '
Resultado: ' + e.outcome
    ).join('
---
').slice(0, 1500) + '
--- FIN EJEMPLOS ---';
    dynamicParts.push(fewShotContext);
  }
} catch (e) { /* few-shot fetch failed, continue */ }

// Build complete dynamic system message
const dynamicSystemMessage = SOFIA_PROMPT + '

' + dynamicParts.join('

');

// ===== CLEAN CHATINPUT (user message only - this is what memoryPostgresChat saves) =====
let messageContent = original.content || '';

// Handle location data
const orderData = original.order_data;
if (orderData && (orderData.latitude || orderData.mapsLink)) {
  let locInfo = '';
  if (orderData.latitude) {
    locInfo = '[Ubicacion GPS del cliente: ' + googleMapsUrl + ']';
  } else if (orderData.mapsLink) {
    locInfo = '[Link de ubicacion del cliente: ' + orderData.mapsLink + ']';
  }
  if (!messageContent || /^https?:///.test(messageContent.trim())) {
    messageContent = locInfo;
  } else {
    messageContent += '
' + locInfo;
  }
} else if (!messageContent && original.has_location_attachment) {
  messageContent = '[El cliente compartio su ubicacion GPS por WhatsApp]';
} else if (!messageContent && original.has_attachment) {
  messageContent = '[El cliente envio un archivo adjunto]';
} else if (!messageContent) {
  messageContent = '[Mensaje del cliente sin texto]';
}

return [{
  json: {
    ...original,
    chatInput: messageContent,
    dynamicSystemMessage: dynamicSystemMessage,
    kb_context: kbContext,
    fewshot_context: fewShotContext
  },
  pairedItem: { item: 0 }
}];

// Extract audio attachment URL from body-level attachments (NOT conversation.messages[0])
const body = $input.item.json.body;
const audioAtt = (body.attachments || []).find(a => a.file_type === 'audio');
const audioUrl = audioAtt?.data_url || audioAtt?.external_url || '';
return { json: { body, audio_url: audioUrl } };

const output = $input.item.json?.output || '';

// Suppress response if handoff is active
try {
  const conv_id = $input.item.json?.conversation_id;
  const acc_id = $input.item.json?.account_id;
  if (conv_id && acc_id) {
    const r = await $helpers.httpRequest({
      method: 'GET',
      url: `https://chat.thebrightidea.ai/api/v1/accounts/${acc_id}/conversations/${conv_id}/labels`,
      headers: {'api_access_token': 'CHATWOOT_TOKEN_REDACTED'}
    });
    if ((r?.payload || []).includes('humano')) {
      return null; // Handoff active - no response to client
    }
  }
} catch(e) {}

if (!output || output.trim().length < 5) {
  const name = $input.item.json?.first_name || $input.item.json?.name || '';
  return { json: { ...($input.item.json || {}), output: 'Un momento ' + (name ? name + ', ' : '') + 'ya le respondo \u2705' } };
}
return $input.item;

