// Reference the original webhook data (Gmail output doesn't have it)
const item = $('Webhook').item.json;
const body = item.body || item;

// Extract customer data
const customerName = body.customer?.name || 'Cliente';
const rawPhone = String(body.customer?.phone || '');

// Clean phone: keep only digits and +
let phone = rawPhone.replace(/[^0-9+]/g, '');

// Only add +595 for local Paraguay numbers (start with 0 or are 9-10 digits without country code)
if (phone.startsWith('0')) {
  phone = '+595' + phone.substring(1);
} else if (!phone.startsWith('+')) {
  // No + prefix: check if it looks like a local number (9-10 digits)
  const digits = phone.replace(/\D/g, '');
  if (digits.length <= 10) {
    phone = '+595' + digits;
  } else {
    phone = '+' + digits;
  }
}

// Last 8 digits for flexible matching
const phoneLast8 = phone.replace(/\D/g, '').slice(-8);

// Extract order data
const product = body.order?.product || 'Lentes Solenne';
const total = body.order?.total || 0;
const quantity = body.order?.quantity || 1;
const orderNumber = body.orderNumber || '';

// Payment info from webhook
const paymentMethod = body.payment?.method || 'pending';
const paymentStatus = body.payment?.status || 'pending';

// Format total with dots (229000 -> "229.000")
const fmtTotal = Number(total).toLocaleString('es-PY');

// Product display name (translate from English if needed)
const productMap = {
  'SOLENNE Red Light Blocking Glasses': 'Lentes Solenne Rojos',
  'SOLENNE Orange Light Blocking Glasses': 'Lentes Solenne Naranjas',
  'SOLENNE Glasses - Personal': 'Lentes Solenne Rojos',
  'SOLENNE Glasses - Kit Duo (x2)': 'Kit Duo (2 Lentes Solenne)',
  'SOLENNE Glasses - Kit Familiar (x3)': 'Kit Familiar (3 Lentes Solenne)'
};
const productDisplay = productMap[product] || product;

// Location check
const mapsLink = body.location?.googleMapsLink || '';
const city = body.location?.city || '';
const address = body.location?.address || '';
const hasGPS = !!(mapsLink && mapsLink.length > 10 && mapsLink.includes('google'));

// Address: use actual address, fallback to city, then 'Direccion pendiente'
const addressText = address || city || 'Direccion pendiente';

return [{ json: {
  phone,
  phone_last8: phoneLast8,
  customer_name: customerName,
  product: productDisplay,
  product_original: product,
  total: fmtTotal,
  total_raw: total,
  quantity,
  order_number: orderNumber,
  payment_method: paymentMethod,
  payment_status: paymentStatus,
  maps_link: mapsLink,
  city,
  address: addressText,
  has_gps: hasGPS
}}];

