// Split FAQ response into max 3 natural parts
const original = $('Extract & Route').item.json;
const faqResponse = original.faq_response || '';
const closing = original.faq_closing || '';

// Split by double newline
const rawParts = faqResponse.split('\n\n').filter(p => p.trim());

let parte1 = faqResponse, parte2 = '', parte3 = '';

if (rawParts.length === 1) {
  parte1 = rawParts[0];
} else if (rawParts.length === 2) {
  parte1 = rawParts[0];
  parte2 = rawParts[1];
} else if (rawParts.length === 3) {
  parte1 = rawParts[0];
  parte2 = rawParts[1];
  parte3 = rawParts[2];
} else if (rawParts.length >= 4) {
  parte1 = rawParts[0] + '\n\n' + rawParts[1];
  parte2 = rawParts[2];
  parte3 = rawParts.slice(3).join('\n\n');
}

// Append closing to the last non-empty part (eliminates separate closing delay)
if (closing) {
  if (parte3.trim()) {
    parte3 = parte3.trim() + '\n\n' + closing;
  } else if (parte2.trim()) {
    parte2 = parte2.trim() + '\n\n' + closing;
  } else {
    parte1 = parte1.trim() + '\n\n' + closing;
  }
}

return { json: {
  ...original,
  parte1: parte1.trim(),
  parte2: parte2.trim(),
  parte3: parte3.trim(),
  has_part2: parte2.trim().length > 0,
  has_part3: parte3.trim().length > 0,
  faq_closing: ''
}};

