const er = $('Extract & Route').item.json;
// Map faq_category to media_type for Send Media subworkflow
// precio → foto_ambos_colores (sends BOTH red and orange photos)
const categoryToMedia = {
  'fotos': 'foto_producto',
  'precio': 'foto_ambos_colores',
  'saludo': null
};
return {
  json: {
    media_type: categoryToMedia[er.faq_category] || 'foto_producto',
    account_id: er.account_id,
    conversation_id: er.conversation_id,
    phone: er.phone,
    faq_category: er.faq_category
  }
};

// Combine all buffered messages into one body for Extract & Route
const originalBody = $('Chatwoot Webhook').first().json.body;
const bufferRaw = $('Read Buffer').first().json.message;
let messages = [];
const raw = Array.isArray(bufferRaw) ? bufferRaw : (bufferRaw ? [bufferRaw] : []);
for (const item of raw) {
  try {
    const msg = typeof item === 'string' ? JSON.parse(item) : item;
    if (msg) messages.push(msg);
  } catch(e) {}
}
const body = JSON.parse(JSON.stringify(originalBody));
if (messages.length > 0) {
  body.content = messages.map(m => m.content).filter(Boolean).join('\n');
  const allAttachments = messages.flatMap(m => m.attachments || []);
  if (allAttachments.length > 0) body.attachments = allAttachments;
  // Use source_id from the LAST buffered message (most recent WhatsApp msg)
  const lastMsg = messages[messages.length - 1];
  if (lastMsg && lastMsg.source_id) {
    body.source_id = lastMsg.source_id;
  }
}
return { json: { body } };

